// A callback is just a function reference passed to another function
function greet(name: string, formatter: (n: string) => string): string {
  return formatter(name);
}

console.log(greet('Alice', n => `Hello, ${n}!`));        // 'Hello, Alice!'
console.log(greet('Bob',   n => n.toUpperCase()));        // 'BOB'

const numbers = [1, 2, 3, 4, 5];

// forEach -- synchronous; callback runs for each item in order
numbers.forEach((n, index) => {
  console.log(index, n);
}); // runs before the next line
console.log('forEach complete'); // prints AFTER all iterations

// map -- synchronous; returns a new array
const doubled = numbers.map(n => n * 2);
console.log(doubled); // [2, 4, 6, 8, 10]

// filter -- synchronous; returns matching items
const evens = numbers.filter(n => n % 2 === 0);
console.log(evens); // [2, 4]

// sort comparison -- synchronous callback
const names = ['Carol', 'Alice', 'Bob'];
names.sort((a, b) => a.localeCompare(b));
console.log(names); // ['Alice', 'Bob', 'Carol']

console.log('1: start');

setTimeout(() => {
  console.log('3: timeout callback'); // fires after delay
}, 1000);

console.log('2: end');
// Output order: 1, 2, 3
// main() runs to completion before the callback queue is checked

import { readFile } from 'fs';

// Error-first: first arg is error, second is result
readFile('/etc/hosts', 'utf8', (err, data) => {
  if (err) {
    console.error('Failed to read file:', err.message);
    return; // exit early -- do not proceed if error
  }
  console.log('File contents:', data);
});

// Pattern in browser code (pre-Promise APIs)
function loadScript(src: string, callback: (err: Error | null) => void) {
  const script = document.createElement('script');
  script.src = src;
  script.onload  = () => callback(null);
  script.onerror = () => callback(new Error(`Failed to load ${src}`));
  document.head.append(script);
}

loadScript('/vendor/chart.js', (err) => {
  if (err) { console.error(err); return; }
  renderChart(); // safe to use Chart here
});

// Deeply nested callbacks -- hard to follow, errors difficult to propagate
getUser(userId, (userErr, user) => {
  if (userErr) { return handleError(userErr); }
  getPosts(user.id, (postsErr, posts) => {
    if (postsErr) { return handleError(postsErr); }
    getComments(posts[0].id, (commentsErr, comments) => {
      if (commentsErr) { return handleError(commentsErr); }
      renderPage(user, posts, comments);
    });
  });
});

// Better -- named functions flatten the nesting
function handleComments(err: Error | null, comments: Comment[]) {
  if (err) { return handleError(err); }
  renderPage(state.user, state.posts, comments);
}

function handlePosts(err: Error | null, posts: Post[]) {
  if (err) { return handleError(err); }
  state.posts = posts;
  getComments(posts[0].id, handleComments);
}

function handleUser(err: Error | null, user: User) {
  if (err) { return handleError(err); }
  state.user = user;
  getPosts(user.id, handlePosts);
}

getUser(userId, handleUser);

// The same operation -- three patterns

// 1. Callback (Node-style)
getUser(userId, (err, user) => {
  if (err) throw err;
  console.log(user.name);
});

// 2. Promise
getUserPromise(userId)
  .then(user => console.log(user.name))
  .catch(err => console.error(err));

// 3. Observable (RxJS / Angular HttpClient)
http.get<User>(`/api/users/${userId}`)
  .pipe(map(user => user.name))
  .subscribe({
    next:  name => console.log(name),
    error: err  => console.error(err),
  });

import { promisify } from 'util';
import { readFile }  from 'fs';

// Node.js: promisify a callback API
const readFileAsync = promisify(readFile);
const content = await readFileAsync('/etc/hosts', 'utf8');

// Browser: manual wrapper
function withPromise<T>(
  fn: (cb: (err: Error | null, result: T) => void) => void
): Promise<T> {
  return new Promise((resolve, reject) => {
    fn((err, result) => {
      if (err) reject(err);
      else resolve(result);
    });
  });
}

// Promisifying the loadScript helper from earlier
const loadScriptAsync = (src: string) =>
  withPromise<void>(cb => loadScript(src, cb));

await loadScriptAsync('/vendor/chart.js');
renderChart();

import { Component, OnInit, OnDestroy } from '@angular/core';

@Component({ selector: 'app-clock', template: '{{ time }}' })
export class ClockComponent implements OnInit, OnDestroy {
  time = '';
  private intervalId!: ReturnType<typeof setInterval>;

  ngOnInit(): void {
    this.intervalId = setInterval(() => {
      // Zone.js patches setTimeout/setInterval -- Angular's change detection
      // runs automatically after the callback executes
      this.time = new Date().toLocaleTimeString();
    }, 1000);
  }

  ngOnDestroy(): void {
    clearInterval(this.intervalId); // must clean up to prevent memory leaks
  }
}

import { NgZone } from '@angular/core';

@Component({ selector: 'app-canvas', template: '<canvas #c></canvas>' })
export class CanvasComponent {
  private zone = inject(NgZone);
  private animId!: number;

  startAnimation(ctx: CanvasRenderingContext2D): void {
    // Run outside Angular zone -- requestAnimationFrame fires very frequently
    // and we do not want change detection on every frame
    this.zone.runOutsideAngular(() => {
      const frame = () => {
        drawFrame(ctx);
        this.animId = requestAnimationFrame(frame);
      };
      this.animId = requestAnimationFrame(frame);
    });
  }

  stopAnimation(): void {
    cancelAnimationFrame(this.animId);
  }
}

import { fromEvent, Observable, bindNodeCallback } from 'rxjs';
import { debounceTime, map } from 'rxjs/operators';
import * as fs from 'fs';

// 1. fromEvent — DOM or Node.js EventEmitter
const clicks$ = fromEvent<MouseEvent>(document, 'click').pipe(
  map(e => ({ x: e.clientX, y: e.clientY }))
);
clicks$.subscribe(pos => console.log(pos));

// 2. new Observable — wraps any single callback
function timeout$(ms: number): Observable<void> {
  return new Observable(observer => {
    const id = setTimeout(() => {
      observer.next();
      observer.complete();
    }, ms);
    return () => clearTimeout(id);   // teardown — called on unsubscribe
  });
}
timeout$(1000).subscribe(() => console.log('1 second elapsed'));

// 3. bindNodeCallback — error-first Node.js APIs
const readFile$ = bindNodeCallback(fs.readFile);
readFile$('config.json', 'utf-8').subscribe({
  next: data => console.log(data),
  error: err => console.error(err),
});

import { Injectable, inject, DestroyRef } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { fromEvent } from 'rxjs';
import { debounceTime } from 'rxjs/operators';

@Injectable({ providedIn: 'root' })
export class ResizeService {
  private destroyRef = inject(DestroyRef);

  readonly windowResize$ = fromEvent(window, 'resize').pipe(
    debounceTime(150),
    takeUntilDestroyed(this.destroyRef)
  );
}

// component usage
class MyComponent {
  private resize = inject(ResizeService);

  ngOnInit() {
    this.resize.windowResize$.subscribe(e => this.recalcLayout());
  }
}

import { fakeAsync, tick } from '@angular/core/testing';

describe('debounce helper', () => {
  function debounce<T>(fn: (v: T) => void, ms: number) {
    let timer: ReturnType<typeof setTimeout>;
    return (v: T) => { clearTimeout(timer); timer = setTimeout(() => fn(v), ms); };
  }

  it('only calls fn once after the delay', fakeAsync(() => {
    const spy = jasmine.createSpy('callback');
    const debounced = debounce(spy, 300);

    debounced('a');
    debounced('b');
    debounced('c');
    expect(spy).not.toHaveBeenCalled();  // not yet

    tick(300);
    expect(spy).toHaveBeenCalledOnceWith('c');
  }));

  it('does not fire if cancelled', fakeAsync(() => {
    const spy = jasmine.createSpy();
    const debounced = debounce(spy, 300);
    debounced('x');
    tick(200);
    // component destroyed before 300 ms — simulate no more ticks
    expect(spy).not.toHaveBeenCalled();
  }));
});

// Testing error-first callbacks with done()
it('loadScript calls back with an error on 404', (done) => {
  function loadScript(src: string, cb: (err: Error | null) => void) {
    const el = document.createElement('script');
    el.src = src;
    el.onerror = () => cb(new Error('Failed to load ' + src));
    el.onload  = () => cb(null);
    document.head.appendChild(el);
  }

  loadScript('https://invalid.example/404.js', (err) => {
    expect(err).toBeTruthy();
    expect(err!.message).toContain('Failed to load');
    done();
  });
});
